DROP TABLE IF EXISTS `control_stock`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `control_stock` (
  `iddeposito` int(11) NOT NULL AUTO_INCREMENT,
  `nombre` varchar(200) DEFAULT NULL,
  `detalle` varchar(200) DEFAULT NULL,
  `unidad` varchar(100) DEFAULT NULL,
  `cantidad` int(11) DEFAULT NULL,
  `idsector` int(11) NOT NULL,
  `idtipo` int(11) NOT NULL,
  `fecha_alta` datetime DEFAULT NULL,
  `estado` varchar(45) DEFAULT 'Activo',
  PRIMARY KEY (`iddeposito`),
  KEY `fk_sector_idx` (`idsector`),
  KEY `fk_tipo_producto_idx` (`idtipo`),
  CONSTRAINT `fk_sector` FOREIGN KEY (`idsector`) REFERENCES `sector` (`idsector`) ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT `fk_tipo_producto` FOREIGN KEY (`idtipo`) REFERENCES `tipo_producto` (`idtipo_producto`) ON DELETE NO ACTION ON UPDATE NO ACTION
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
