CREATE TABLE `grupof` (
  `idgrupo` int(11) NOT NULL AUTO_INCREMENT COMMENT 'TRIAL',
  `idempleado` int(11) NOT NULL COMMENT 'TRIAL',
  `apellido` varchar(60) NOT NULL COMMENT 'TRIAL',
  `nombre` varchar(60) NOT NULL COMMENT 'TRIAL',
  `dni` int(11) NOT NULL COMMENT 'TRIAL',
  `fnac` longtext NOT NULL COMMENT 'TRIAL',
  `parentesco` varchar(30) NOT NULL COMMENT 'TRIAL',
  `escolaridad` varchar(50) DEFAULT NULL COMMENT 'TRIAL',
  `trial685` char(1) DEFAULT NULL COMMENT 'TRIAL',
  `trial327` char(1) DEFAULT NULL COMMENT 'TRIAL',
  PRIMARY KEY (`idgrupo`),
  KEY `idx_idempleado` (`idempleado`),
  CONSTRAINT `grupof_ibfk_1` FOREIGN KEY (`idempleado`) REFERENCES `empleado` (`idempleado`)
) ENGINE=InnoDB AUTO_INCREMENT=132 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci COMMENT='TRIAL';
