--
-- Table structure for table `recaudacion`
--

DROP TABLE IF EXISTS `recaudacion`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `recaudacion` (
  `idrecaudacion` int(11) NOT NULL AUTO_INCREMENT COMMENT 'TRIAL',
  `fecha` date DEFAULT NULL COMMENT 'TRIAL',
  `nrecibo` int(11) DEFAULT NULL COMMENT 'TRIAL',
  `idcontribuyente` int(11) DEFAULT NULL COMMENT 'TRIAL',
  `idconcepto` int(11) DEFAULT NULL COMMENT 'TRIAL',
  `monto` double DEFAULT NULL COMMENT 'TRIAL',
  `idmodo` int(11) DEFAULT NULL COMMENT 'TRIAL',
  `trial375` char(1) DEFAULT NULL COMMENT 'TRIAL',
  `modopago` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`idrecaudacion`),
  KEY `ck_contrib` (`idcontribuyente`),
  KEY `ck_concep` (`idconcepto`),
  KEY `fk_idmodo` (`idmodo`),
  CONSTRAINT `ck_concep` FOREIGN KEY (`idconcepto`) REFERENCES `concepto` (`idconcepto`) ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT `ck_contrib` FOREIGN KEY (`idcontribuyente`) REFERENCES `contribuyente` (`idcontribuyente`) ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT `fk_idmodo` FOREIGN KEY (`idmodo`) REFERENCES `modo` (`idmodo`) ON DELETE NO ACTION ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=7193 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci COMMENT='TRIAL';
/*!40101 SET character_set_client = @saved_cs_client */;

